// nodes/filterNode.js — Data filter / transform node
import { BaseNode } from '../components/BaseNode';

const config = {
  title: 'Filter',
  icon: '🔽',
  color: 'var(--pf-orange)',
  fields: [
    { key: 'mode', label: 'Mode', type: 'select', defaultValue: 'include',
      options: ['include', 'exclude', 'transform', 'truncate'] },
    { key: 'expression', label: 'Expression', type: 'text',
      placeholder: 'e.g. word count > 100' },
    { key: 'maxLength', label: 'Max length', type: 'text', placeholder: '500' },
  ],
  inputs:  [{ id: 'data',   label: 'Data'   }],
  outputs: [{ id: 'result', label: 'Result' }],
};

export const FilterNode = (props) => <BaseNode {...props} config={config} />;
